1	// resolver_agent_metrics.go implements the agentMetrics(window, groupBy)
2	// query (Story 11). Aggregations are computed from the agentmetrics package
3	// (run-store first, .ddx/executions bundles fallback) and cached per
4	// (project, axis, window) keyed on a revision fingerprint of the underlying
5	// data sources. The fingerprint covers the run-store dir, the bundles dir,
6	// and the .ddx/beads-archive.jsonl file so the cache survives an ADR-004
7	// archive move (closed beads moved out of beads.jsonl into beads-archive
8	// flip the fingerprint and force a re-aggregate).
9	package graphql
10	
11	import (
12		"context"
13		"crypto/sha256"
14		"fmt"
15		"os"
16		"path/filepath"
17		"sort"
18		"sync"
19		"time"
20	
21		"github.com/DocumentDrivenDX/ddx/internal/agentmetrics"
22	)
23	
24	// agentMetricsCacheEntry is one cached aggregation. fingerprint is the
25	// revision string the entry was computed against; on lookup the resolver
26	// recomputes the current fingerprint and serves the entry only when they
27	// match.
28	type agentMetricsCacheEntry struct {
29		fingerprint string
30		result      *AgentMetricsResult
31	}
32	
33	// agentMetricsCache is process-global. Multi-project servers key by the
34	// effective workingDir so two projects never collide.
35	var agentMetricsCache = struct {
36		sync.Mutex
37		byKey map[string]agentMetricsCacheEntry
38	}{byKey: map[string]agentMetricsCacheEntry{}}
39	
40	// AgentMetrics is the resolver for the agentMetrics field.
41	func (r *queryResolver) AgentMetrics(ctx context.Context, window AgentMetricsWindow, groupBy AgentMetricsAxis) (*AgentMetricsResult, error) {
42		if !window.IsValid() {
43			return nil, fmt.Errorf("agentMetrics: invalid window %q", window)
44		}
45		if !groupBy.IsValid() {
46			return nil, fmt.Errorf("agentMetrics: invalid groupBy %q", groupBy)
47		}
48		wd := r.workingDir(ctx)
49		fp := agentMetricsFingerprint(wd)
50		cacheKey := wd + "|" + string(window) + "|" + string(groupBy)
51	
52		agentMetricsCache.Lock()
53		if cached, ok := agentMetricsCache.byKey[cacheKey]; ok && cached.fingerprint == fp {
54			agentMetricsCache.Unlock()
55			return cached.result, nil
56		}
57		agentMetricsCache.Unlock()
58	
59		attempts, err := agentmetrics.LoadAttempts(wd)
60		if err != nil {
61			return nil, fmt.Errorf("agentMetrics: load attempts: %w", err)
62		}
63		cutoff := time.Now().UTC().Add(-windowDuration(window))
64		rows := buildAgentMetricsRows(attempts, cutoff, groupBy)
65		result := &AgentMetricsResult{
66			Window:   window,
67			GroupBy:  groupBy,
68			Revision: fp,
69			Rows:     rows,
70		}
71		agentMetricsCache.Lock()
72		agentMetricsCache.byKey[cacheKey] = agentMetricsCacheEntry{fingerprint: fp, result: result}
73		agentMetricsCache.Unlock()
74		return result, nil
75	}
76	
77	// windowDuration maps the schema enum to a Duration. Falls back to the 7d
78	// default for unknown values (the IsValid guard above already rejects them).
79	func windowDuration(w AgentMetricsWindow) time.Duration {
80		switch w {
81		case AgentMetricsWindowW24h:
82			return 24 * time.Hour
83		case AgentMetricsWindowW30d:
84			return 30 * 24 * time.Hour
85		default:
86			return 7 * 24 * time.Hour
87		}
88	}
89	
90	// buildAgentMetricsRows groups attempts by axis, applies the window cutoff,
91	// and computes per-bucket aggregates. Output is sorted by attempt count
92	// descending then key ascending so the UI gets a stable ordering.
93	func buildAgentMetricsRows(attempts []agentmetrics.Attempt, cutoff time.Time, axis AgentMetricsAxis) []*AgentMetricsRow {
94		type acc struct {
95			durations    []int
96			costs        []float64
97			inTokens     []int
98			outTokens    []int
99			successes    int
100			totalCost    float64
101			lastFinished time.Time
102		}
103		groups := map[string]*acc{}
104		for _, a := range attempts {
105			if !a.StartedAt.IsZero() && a.StartedAt.Before(cutoff) {
106				continue
107			}
108			key := axisKey(a, axis)
109			if key == "" {
110				continue
111			}
112			g, ok := groups[key]
113			if !ok {
114				g = &acc{}
115				groups[key] = g
116			}
117			g.durations = append(g.durations, a.DurationMS)
118			g.costs = append(g.costs, a.CostUSD)
119			g.inTokens = append(g.inTokens, a.InputTokens)
120			g.outTokens = append(g.outTokens, a.OutputTokens)
121			g.totalCost += a.CostUSD
122			if a.Bucket.Successful() {
123				g.successes++
124			}
125			ts := a.FinishedAt
126			if ts.IsZero() {
127				ts = a.StartedAt
128			}
129			if !ts.IsZero() && ts.After(g.lastFinished) {
130				g.lastFinished = ts
131			}
132		}
133	
134		out := make([]*AgentMetricsRow, 0, len(groups))
135		for key, g := range groups {
136			attemptCount := len(g.durations)
137			row := &AgentMetricsRow{
138				Key:              key,
139				Attempts:         attemptCount,
140				Successes:        g.successes,
141				SuccessRate:      ratio(g.successes, attemptCount),
142				MeanDurationMs:   meanInt(g.durations),
143				P50DurationMs:    percentileInt(g.durations, 50),
144				P95DurationMs:    percentileInt(g.durations, 95),
145				MeanCostUsd:      meanFloat(g.costs),
146				MeanInputTokens:  meanInt(g.inTokens),
147				MeanOutputTokens: meanInt(g.outTokens),
148			}
149			if g.successes > 0 {
150				eff := g.totalCost / float64(g.successes)
151				row.EffectiveCostPerSuccessUsd = &eff
152			}
153			if !g.lastFinished.IsZero() {
154				s := g.lastFinished.UTC().Format(time.RFC3339)
155				row.LastSeenAt = &s
156			}
157			out = append(out, row)
158		}
159		sort.Slice(out, func(i, j int) bool {
160			if out[i].Attempts != out[j].Attempts {
161				return out[i].Attempts > out[j].Attempts
162			}
163			return out[i].Key < out[j].Key
164		})
165		return out
166	}
