168	// axisKey extracts the bucket label for one Attempt against one axis. Empty
169	// string means "skip this attempt for this axis" (e.g. a model-axis bucket
170	// for a result.json with no model field).
171	func axisKey(a agentmetrics.Attempt, axis AgentMetricsAxis) string {
172		switch axis {
173		case AgentMetricsAxisModel:
174			return a.Model
175		case AgentMetricsAxisHarness:
176			return a.Harness
177		case AgentMetricsAxisProvider:
178			return a.Provider
179		case AgentMetricsAxisTier:
180			return a.Tier
181		}
182		return ""
183	}
