185	func ratio(num, denom int) float64 {
186		if denom == 0 {
187			return 0
188		}
189		return float64(num) / float64(denom)
190	}
191	
192	func meanInt(xs []int) float64 {
193		if len(xs) == 0 {
194			return 0
195		}
196		var sum int
197		for _, v := range xs {
198			sum += v
199		}
200		return float64(sum) / float64(len(xs))
201	}
202	
203	func meanFloat(xs []float64) float64 {
204		if len(xs) == 0 {
205			return 0
206		}
207		var sum float64
208		for _, v := range xs {
209			sum += v
210		}
211		return sum / float64(len(xs))
212	}
213	
214	// percentileInt returns the nearest-rank percentile of xs (0-100). For p50 on
215	// an even-length slice it picks the lower of the two middle values; that
216	// matches Go's standard nearest-rank choice and is sufficient for the
217	// operator-facing summary.
218	func percentileInt(xs []int, p int) int {
219		if len(xs) == 0 {
220			return 0
221		}
222		sorted := append([]int(nil), xs...)
223		sort.Ints(sorted)
224		rank := (p * len(sorted)) / 100
225		if rank >= len(sorted) {
226			rank = len(sorted) - 1
227		}
228		return sorted[rank]
229	}
