231	// agentMetricsFingerprint produces a stable revision string for the
232	// agentmetrics inputs at workingDir. The hash inputs are: the .ddx/exec/runs
233	// directory listing (name + size + modtime), the .ddx/executions directory
234	// listing of result.json files, and the .ddx/beads-archive.jsonl file's
235	// stat. Any add/remove/modify in those sources flips the fingerprint and
236	// invalidates the cache. The fingerprint survives ADR-004 archive moves
237	// because the archive file is included.
238	func agentMetricsFingerprint(workingDir string) string {
239		h := sha256.New()
240		addDir(h, filepath.Join(workingDir, ".ddx", "exec", "runs"), "")
241		addDir(h, filepath.Join(workingDir, ".ddx", "executions"), "result.json")
242		addStat(h, filepath.Join(workingDir, ".ddx", "beads-archive.jsonl"))
243		addStat(h, filepath.Join(workingDir, ".ddx", "beads.jsonl"))
244		return fmt.Sprintf("%x", h.Sum(nil))
245	}
246	
247	func addDir(h interface{ Write([]byte) (int, error) }, dir, requireChild string) {
248		entries, err := os.ReadDir(dir)
249		if err != nil {
250			fmt.Fprintf(writerOf(h), "missing:%s\n", dir)
251			return
252		}
253		names := make([]string, 0, len(entries))
254		for _, e := range entries {
255			names = append(names, e.Name())
256		}
257		sort.Strings(names)
258		for _, name := range names {
259			full := filepath.Join(dir, name)
260			if requireChild != "" {
261				full = filepath.Join(full, requireChild)
262			}
263			addStat(h, full)
264		}
265	}
266	
267	func addStat(h interface{ Write([]byte) (int, error) }, path string) {
268		info, err := os.Stat(path)
269		if err != nil {
270			fmt.Fprintf(writerOf(h), "absent:%s\n", path)
271			return
272		}
273		fmt.Fprintf(writerOf(h), "%s:%d:%d\n", path, info.Size(), info.ModTime().UnixNano())
274	}
275	
276	// writerOf adapts an io.Writer-like to fmt.Fprintf. Kept tiny so the helpers
277	// above stay one-liners.
278	func writerOf(h interface{ Write([]byte) (int, error) }) interface{ Write([]byte) (int, error) } {
279		return h
280	}
