11	// writeRun seeds one FEAT-010 run-store record under workingDir.
12	func writeRun(t *testing.T, workingDir, name, body string) {
13		t.Helper()
14		dir := filepath.Join(workingDir, ".ddx", "exec", "runs")
15		if err := os.MkdirAll(dir, 0o755); err != nil {
16			t.Fatalf("mkdir: %v", err)
17		}
18		if err := os.WriteFile(filepath.Join(dir, name), []byte(body), 0o644); err != nil {
19			t.Fatalf("write: %v", err)
20		}
21	}
