112	// resetCache clears the process-global cache so each test sees a clean
113	// slate. Without this, tests that share an axis/window collide on cache
114	// hits and never rebuild against fresh fixtures.
115	func resetAgentMetricsCache() {
116		agentMetricsCache.Lock()
117		agentMetricsCache.byKey = map[string]agentMetricsCacheEntry{}
118		agentMetricsCache.Unlock()
119	}
