121	func TestAgentMetrics_GroupByModel(t *testing.T) {
122		resetAgentMetricsCache()
123		wd := fixtureWorkingDir(t)
124		r := newTestResolver(t, wd)
125		res, err := r.AgentMetrics(context.Background(), AgentMetricsWindowW7d, AgentMetricsAxisModel)
126		if err != nil {
127			t.Fatalf("AgentMetrics: %v", err)
128		}
129		if len(res.Rows) != 2 {
130			t.Fatalf("model rows = %d, want 2", len(res.Rows))
131		}
132		// sonnet bucket: 2 attempts, 1 success.
133		row := findRow(t, res.Rows, "sonnet")
134		if row.Attempts != 2 || row.Successes != 1 {
135			t.Fatalf("sonnet: %+v", row)
136		}
137		if row.SuccessRate != 0.5 {
138			t.Fatalf("sonnet successRate = %f, want 0.5", row.SuccessRate)
139		}
140		// MeanCost = (1.0 + 2.0)/2 = 1.5; effective = 3.0/1 success = 3.0.
141		if row.MeanCostUsd != 1.5 {
142			t.Fatalf("sonnet meanCost = %f, want 1.5", row.MeanCostUsd)
143		}
144		if row.EffectiveCostPerSuccessUsd == nil || *row.EffectiveCostPerSuccessUsd != 3.0 {
145			t.Fatalf("sonnet effectiveCost = %v, want 3.0", row.EffectiveCostPerSuccessUsd)
146		}
147		if row.MeanInputTokens != 150 || row.MeanOutputTokens != 65 {
148			t.Fatalf("sonnet tokens: in=%f out=%f", row.MeanInputTokens, row.MeanOutputTokens)
149		}
150		// gpt5 bucket: 1 attempt, 1 success (already_satisfied counts).
151		gpt := findRow(t, res.Rows, "gpt5")
152		if gpt.Attempts != 1 || gpt.Successes != 1 {
153			t.Fatalf("gpt5: %+v", gpt)
154		}
155		if res.Window != AgentMetricsWindowW7d || res.GroupBy != AgentMetricsAxisModel {
156			t.Fatalf("echo fields: %+v", res)
157		}
158		if res.Revision == "" {
159			t.Fatalf("revision must not be empty")
160		}
161	}
