250	// TestAgentMetrics_RevisionCache asserts the per-axis cache keys results on
251	// the run-store fingerprint and invalidates when a new run is added.
252	func TestAgentMetrics_RevisionCache(t *testing.T) {
253		resetAgentMetricsCache()
254		wd := fixtureWorkingDir(t)
255		r := newTestResolver(t, wd)
256	
257		first, err := r.AgentMetrics(context.Background(), AgentMetricsWindowW7d, AgentMetricsAxisModel)
258		if err != nil {
259			t.Fatalf("first: %v", err)
260		}
261		// Same call returns identical pointer: cache hit.
262		cached, err := r.AgentMetrics(context.Background(), AgentMetricsWindowW7d, AgentMetricsAxisModel)
263		if err != nil {
264			t.Fatalf("cached: %v", err)
265		}
266		if cached != first {
267			t.Fatalf("expected cache hit (same pointer); got distinct results")
268		}
269	
270		// Add a new attempt — fingerprint must change, cache must invalidate.
271		now := time.Now().UTC().Format(time.RFC3339)
272		writeRun(t, wd, "d.json", `{
273			"id":"att-4","layer":"try","status":"success",
274			"harness":"claude","provider":"anthropic","model":"sonnet",
275			"cost_usd":1,"duration_ms":1,"started_at":"`+now+`","completed_at":"`+now+`"
276		}`)
